#include "interface.h"
#include "fast_float/fast_float.h"

#include <string>

double parse_sum(const std::string& input) {
  const char* p = input.data();
  const char* end = p + input.size();
  double sum = 0.0;

  while (p < end) {
    // Skip leading whitespace to roughly match strtod behavior
    while (p < end) {
      char c = *p;
      if (c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == '\f' || c == '\v') {
        ++p;
      } else {
        break;
      }
    }
    if (p >= end) break;

    double value;
    auto r = fast_float::from_chars(p, end, value);
    if (r.ptr == p) {
      // No progress: stop parsing
      break;
    }
    sum += value;
    p = r.ptr;

    // Advance past delimiter if present immediately after the number
    if (p < end && *p == ';') {
      ++p;
    }
  }

  return sum;
}
